				ByteBuffer buffer = engine.outQueue.take();
				ostream.write( buffer.array(), 0, buffer.limit() );
				ostream.flush();
			}
		} catch ( InterruptedException e ) {
			for (ByteBuffer buffer : engine.outQueue) {
				ostream.write( buffer.array(), 0, buffer.limit() );
				ostream.flush();
			}
			Thread.currentThread().interrupt();
		}
	} catch ( IOException e ) {
		handleIOException( e );
	} finally {
		closeSocket();
		writeThread = null;
	}
}

