private void consumeFutureUninterruptible( Future<?> f ) {
	try {
		boolean interrupted = false;
		while ( true ) {
			try {
				f.get();
				break;
			} catch ( InterruptedException e ) {
				interrupted = true;
			}
		}
		if( interrupted )
			Thread.currentThread().interrupt();
	} catch ( ExecutionException e ) {
		throw new RuntimeException( e );
	}
}

